import{_ as o,C as s,o as n,c as i,j as t,a,E as l,ag as d}from"./chunks/framework.DLWhSH9p.js";const y=JSON.parse('{"title":"Jobs & Workers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/jobs.md","filePath":"guide/jobs.md"}'),h={name:"guide/jobs.md"};function p(u,e,c,g,b,m){const r=s("SchemeImage");return n(),i("div",null,[e[0]||(e[0]=t("h1",{id:"jobs-workers",tabindex:"-1"},[a("Jobs & Workers "),t("a",{class:"header-anchor",href:"#jobs-workers","aria-label":'Permalink to "Jobs & Workers"'},"​")],-1)),e[1]||(e[1]=t("p",null,[a("Long-running tasks in CRAFT Studio run as background jobs so the UI stays responsive. Jobs are "),t("strong",null,"channel-scoped"),a(" and — except for a handful of always-on tasks like TTS and resource downloads — "),t("strong",null,"premium-only"),a(".")],-1)),l(r,{name:"jobs-panel",alt:"Jobs Panel"}),e[2]||(e[2]=d('<h2 id="opening-the-jobs-panel" tabindex="-1">Opening the Jobs panel <a class="header-anchor" href="#opening-the-jobs-panel" aria-label="Permalink to &quot;Opening the Jobs panel&quot;">​</a></h2><p>Click the <strong>channel pill</strong> in the top chrome, then <strong>Jobs</strong> in the dropdown. The entry only appears for premium users (admin auto-qualifies — see <a href="/guide/auth.html">Roles</a>).</p><h2 id="what-runs-as-a-job" tabindex="-1">What runs as a job <a class="header-anchor" href="#what-runs-as-a-job" aria-label="Permalink to &quot;What runs as a job&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Job</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Orchestrate</strong></td><td>Drives the 8-stage Episode pipeline with quality gates and feedback loops</td></tr><tr><td><strong>Idea</strong></td><td>AI idea generation in character voice</td></tr><tr><td><strong>Proposals</strong></td><td>AI-scored proposals with trend analysis</td></tr><tr><td><strong>Fact-check</strong></td><td>Claim verification across the script</td></tr><tr><td><strong>Humanize</strong></td><td>Detect and rewrite AI-sounding passages</td></tr><tr><td><strong>TTS</strong></td><td>Text-to-speech rendering and merge</td></tr><tr><td><strong>Discover</strong></td><td>YouTube research (yt-dlp) with progressive filtering</td></tr><tr><td><strong>Resource download</strong></td><td>Pull assets from the 14 sources</td></tr><tr><td><strong>Render</strong></td><td>Remotion → MP4 export (Chromium)</td></tr></tbody></table><h2 id="lifecycle" tabindex="-1">Lifecycle <a class="header-anchor" href="#lifecycle" aria-label="Permalink to &quot;Lifecycle&quot;">​</a></h2><p>Every job goes through the same four states you&#39;ll see in the panel:</p><ol><li><strong>Queued</strong> — submitted, waiting for a worker slot.</li><li><strong>Running</strong> — a worker picked it up; progress streams live over server-sent events.</li><li><strong>Completed</strong> — success; result is persisted (e.g. new script, rendered MP4).</li><li><strong>Failed</strong> — error captured; failed jobs retry automatically up to three times before requiring manual intervention.</li></ol><p>Each job row expands to show streamed output, duration, and (where applicable) a link to the produced artifact.</p><h2 id="cancellation" tabindex="-1">Cancellation <a class="header-anchor" href="#cancellation" aria-label="Permalink to &quot;Cancellation&quot;">​</a></h2><p>Any running job can be cancelled from its row. Multi-stage jobs (the 8-stage pipeline) stop cleanly at the next stage boundary so they don&#39;t leave half-finished artifacts behind.</p><h2 id="why-jobs" tabindex="-1">Why jobs? <a class="header-anchor" href="#why-jobs" aria-label="Permalink to &quot;Why jobs?&quot;">​</a></h2><p>Running work off the main request path means:</p><ul><li>The studio stays interactive while a 20-minute video renders.</li><li>Failures are recoverable — the job can retry, be cancelled, or kicked off again with tweaked inputs.</li><li>Long pipelines (Episodes) can span hours without timing out anything.</li></ul><h2 id="real-time-updates" tabindex="-1">Real-time updates <a class="header-anchor" href="#real-time-updates" aria-label="Permalink to &quot;Real-time updates&quot;">​</a></h2><p>While a job is running, its progress appears in two places:</p><ul><li><strong>The Jobs panel</strong> — live-streamed output, stage updates, and status chips.</li><li><strong>The panel that initiated it</strong> — e.g. a streaming script appears in the editor as the model writes it; a generated image appears in the gallery the moment it&#39;s ready.</li></ul>',16))])}const k=o(h,[["render",p]]);export{y as __pageData,k as default};
